#!/usr/bin/env node
'use strict';

const crypto = require('crypto');
const admin = require('firebase-admin');

const PROJECT_DEFAULT = 'gestordepesquisa';
const ORG_ID = 'org_valora_prd';
const FORM_ID = 'form_valora_insight_prd';
const SURVEY_ID = 'survey_valora_insight_essencial_prd';
const SOURCE = 'bootstrap_prd';
const MODULE_IDS = ['diagnosticos','formularios','pesquisas','convitesEmail','respostas','relatorios','certificados','planoAcao','valorabot','atendimento','notificacoes','financeiro','integracoes','logs','whiteLabel'];

function arg(name, fallback = '') { const i = process.argv.indexOf(`--${name}`); return i >= 0 ? (process.argv[i + 1] && !process.argv[i + 1].startsWith('--') ? process.argv[i + 1] : true) : fallback; }
function has(name) { return process.argv.includes(`--${name}`); }
function iso(days = 0) { const d = new Date(); d.setUTCDate(d.getUTCDate() + days); return d.toISOString(); }
function sha256(v) { return crypto.createHash('sha256').update(String(v)).digest('hex'); }
function token(bytes = 32) { return crypto.randomBytes(bytes).toString('base64url'); }
function strongPassword() { return `${token(9)}aA1!${token(8)}`; }
function logSecretSafe(label, value) { console.log(`${label}: ${value ? '[informado/gerado - não exibido]' : '[não informado]'}`); }

const projectId = String(arg('project', PROJECT_DEFAULT));
const apply = has('apply');
const dryRun = has('dry-run') || !apply;
const overwrite = has('overwrite');
const merge = has('merge') || !overwrite;
if (overwrite && arg('confirm-overwrite') !== projectId) {
  console.error(`--overwrite exige confirmação explícita: --confirm-overwrite ${projectId}`);
  process.exit(2);
}
const adminEmail = String(arg('admin-email', 'admin@valoragroup.com.br')).toLowerCase();
const adminName = String(arg('admin-name', 'Admin Valora'));
const providedPassword = arg('admin-password', '');
const adminPassword = providedPassword || strongPassword();
const seedDemoSurvey = has('seed-demo-survey') || true;
const seedDemoResponse = has('seed-demo-response');
const surveyToken = token(32);

function plans(now) { return [
  { id:'essential', name:'Essencial', description:'Para empresas que querem iniciar a leitura de maturidade organizacional com uma jornada simples, segura e rápida.', audience:'Empresas iniciando diagnóstico com jornada simples.', commercialBadge:'Início rápido', price:0, priceLabel:'Sob consulta', maxActiveSurveys:1, maxResponsesMonth:100, maxManagers:1, maxEmployees:100, maxEmailsMonth:200, enabledModules:['diagnosticos','formularios','pesquisas','respostas','relatorios','certificados','valorabot','atendimento','notificacoes'], features:['Diagnóstico essencial','Link seguro','Dashboard básico','Resultado instantâneo','LGPD','Suporte padrão'], ctaLabel:'Começar diagnóstico', highlighted:false, status:'active', createdAt:now, updatedAt:now },
  { id:'professional', name:'Profissional', description:'Para empresas que precisam acompanhar cultura, governança, pessoas e maturidade com relatórios, convites e plano de ação.', audience:'Empresas em crescimento com acompanhamento recorrente.', commercialBadge:'Mais escolhido', price:0, priceLabel:'Sob consulta', maxActiveSurveys:8, maxResponsesMonth:800, maxManagers:8, maxEmployees:500, maxEmailsMonth:1200, enabledModules:['diagnosticos','formularios','pesquisas','convitesEmail','respostas','relatorios','certificados','planoAcao','valorabot','atendimento','notificacoes','logs'], features:['Múltiplas pesquisas','Convites','Relatórios por dimensão','Plano de ação','ValoraBot','Suporte prioritário'], ctaLabel:'Evoluir minha gestão', highlighted:true, status:'active', createdAt:now, updatedAt:now },
  { id:'corporate', name:'Corporativo', description:'Para organizações que precisam de governança contínua, múltiplas áreas, relatórios avançados e acompanhamento estratégico.', audience:'Organizações multiárea com governança contínua.', commercialBadge:'Governança avançada', price:0, priceLabel:'Sob consulta', maxActiveSurveys:20, maxResponsesMonth:3000, maxManagers:25, maxEmployees:3000, maxEmailsMonth:5000, enabledModules:MODULE_IDS, features:['Múltiplos gestores','Relatórios avançados','Central de atendimento','Integrações','Logs','White label'], ctaLabel:'Falar com especialista', highlighted:false, status:'active', createdAt:now, updatedAt:now },
  { id:'enterprise', name:'Enterprise / Consultivo', description:'Para grupos, redes, consultorias ou operações complexas que precisam de implantação assistida, módulos sob medida e governança executiva.', audience:'Grupos, redes, consultorias e operações complexas.', commercialBadge:'Sob medida', price:0, priceLabel:'Sob contrato', maxActiveSurveys:-1, maxResponsesMonth:10000, maxManagers:50, maxEmployees:10000, maxEmailsMonth:15000, enabledModules:MODULE_IDS, features:['Limites sob contrato','Implantação assistida','Módulos sob medida','Governança executiva','SLA específico'], ctaLabel:'Solicitar proposta', highlighted:false, status:'active', createdAt:now, updatedAt:now }
]; }
function modules(now) { return MODULE_IDS.map(id => ({ id, name: ({diagnosticos:'Diagnósticos',formularios:'Formulários',pesquisas:'Pesquisas',convitesEmail:'Convites por e-mail',respostas:'Respostas',relatorios:'Relatórios',certificados:'Certificados',planoAcao:'Plano de ação',valorabot:'ValoraBot',atendimento:'Atendimento',notificacoes:'Notificações',financeiro:'Financeiro',integracoes:'Integrações',logs:'Logs',whiteLabel:'White label'})[id], description:`Módulo ${id} do Valora Pulse.`, enabled:true, commercialCategory:id, createdAt:now, updatedAt:now })); }
function form(now) { const dims=['Cultura e Pessoas','Liderança','Governança','Processos','Comunicação','Crescimento'].map((name,i)=>({id:name.toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g,'').replace(/\s+/g,'_'),name,description:`Avalia ${name.toLowerCase()} de forma prática.`})); const qs=['As pessoas compreendem o propósito e os valores da organização.','As lideranças comunicam direção clara e acompanham prioridades.','Papéis, responsabilidades e critérios de decisão estão claros.','Os processos apoiam produtividade, qualidade e continuidade.','A comunicação interna favorece alinhamento, confiança e colaboração.','A organização está preparada para crescer de forma sustentável.'].map((text,i)=>({id:`q${i+1}`,text,help:'Responda de 1 (discordo totalmente) a 5 (concordo totalmente).',dimensionId:dims[i].id,dimensionName:dims[i].name,type:'scale',required:true,weight:1,maxScore:5,options:[]})); return {id:FORM_ID,companyId:'',global:true,isGlobal:true,name:'Valora Insight™ — Diagnóstico Estratégico de Maturidade Organizacional',description:'Diagnóstico inicial para mapear maturidade organizacional com linguagem executiva e não técnica.',timeMin:5,scoringMethod:'weightedAverage',dimensions:dims,questions:qs,resultBands:[{min:0,max:39,label:'Inicial',recommendation:'Priorize fundamentos e plano de ação.'},{min:40,max:69,label:'Em evolução',recommendation:'Fortaleça processos e acompanhamento.'},{min:70,max:100,label:'Maduro',recommendation:'Sustente governança e melhoria contínua.'}],lgpdText:'Ao responder, você autoriza o tratamento dos dados para fins de diagnóstico organizacional, conforme LGPD.',status:'active',createdAt:now,updatedAt:now,source:SOURCE}; }
function docs(now) { const planId='professional'; return [
  ['settings','global',{appName:'Valora Pulse',contactEmail:'contato@valoragroup.com.br',featuredSurveyId:SURVEY_ID,whatsappEnabled:false,whatsappNumber:'',lgpdText:'Dados tratados conforme LGPD para execução da plataforma Valora Pulse.',faq:[{q:'Como acesso?',a:'Use seu e-mail cadastrado e senha ou redefinição de senha.'}],email:{mode:'functions',senderName:'Valora Group',senderEmail:'no-reply@valoragroup.com.br'},createdAt:now,updatedAt:now,source:SOURCE}],
  ['organizations',ORG_ID,{id:ORG_ID,name:'Valora Group',publicName:'Valora Group',slug:'valora-group',status:'active',planId,subscription:{planId,planName:'Profissional',status:'active',billingStatus:'manual',startedAt:now},brand:{primaryColor:'#103b5b',secondaryColor:'#155e75',accentColor:'#f59e0b'},settings:{contactEmail:'contato@valoragroup.com.br',defaultSurveyExpirationDays:90,allowPublicResults:true,allowParticipantCertificates:true},createdAt:now,updatedAt:now,source:SOURCE}],
  ['companies',ORG_ID,{id:ORG_ID,name:'Valora Group',publicName:'Valora Group',slug:'valora-group',status:'active',planId,createdAt:now,updatedAt:now,source:SOURCE}],
  ['forms',FORM_ID,form(now)],
  ['surveys',SURVEY_ID,{id:SURVEY_ID,companyId:ORG_ID,formId:FORM_ID,title:'Valora Insight™ — Diagnóstico Essencial',description:'Pesquisa padrão ativa para primeiro acesso PRD.',status:'active',startsAt:now,expiresAt:iso(90),tokenHash:sha256(surveyToken),allowRepeat:true,showResult:true,lgpdRequired:true,requireIdentification:true,responseCount:0,createdAt:now,updatedAt:now,source:SOURCE}]
]; }
function kb(now){return ['O que é o Valora Pulse?','Como responder uma pesquisa?','Como interpretar resultado?','Como baixar certificado?','Como cadastrar funcionários?','Como criar pesquisa?','Como falar com suporte?','Privacidade e segurança.'].map((title,i)=>({id:`kb_prd_${i+1}`,title,category:'primeiro_acesso',content:`${title} Conteúdo inicial da base de conhecimento Valora Pulse para PRD.`,status:'published',createdAt:now,updatedAt:now,source:SOURCE}));}
function support(now){ const cats=['acesso_login','pesquisa_publica','duvida_lgpd','cadastro_funcionario','envio_convite','respostas_resultados','relatorios','plano_assinatura','erro_tecnico','financeiro','outros'].map(id=>({id,name:id.replace(/_/g,' '),description:`Categoria ${id}`,enabled:true,createdAt:now,updatedAt:now,source:SOURCE})); const slas=['baixa','media','alta','critica'].map((id,i)=>({id,name:id,priority:id,firstResponseHours:[24,8,4,1][i],resolutionHours:[72,48,24,8][i],enabled:true,createdAt:now,updatedAt:now,source:SOURCE})); return {cats,slas};}
async function setDoc(db, collection, id, data) { const exists = await db.collection(collection).doc(id).get(); const action = exists.exists ? (overwrite ? 'overwrite' : 'merge') : 'create'; console.log(`${apply?'APPLY':'DRY'} ${action} ${collection}/${id}`); if (!apply) return; await db.collection(collection).doc(id).set(data, { merge }); }
async function main(){ console.log(`Projeto: ${projectId} | modo: ${apply?'APPLY':'DRY-RUN'} | escrita: ${overwrite?'overwrite':'merge'}`); logSecretSafe('Senha admin', adminPassword); if (!apply) console.log('Sem --apply: nenhuma escrita será executada.'); if (apply) admin.initializeApp({ projectId }); const db = apply ? admin.firestore() : null; const now = iso(); if (apply) { let user; try { user = await admin.auth().getUserByEmail(adminEmail); console.log(`Auth admin existente: ${user.uid}`); } catch (e) { if (e.code !== 'auth/user-not-found') throw e; user = await admin.auth().createUser({email:adminEmail,displayName:adminName,password:adminPassword,emailVerified:false,disabled:false}); console.log(`Auth admin criado: ${user.uid}`); if (!providedPassword) console.log('Senha temporária gerada no processo; não foi exibida. Envie reset de senha pelo Firebase Console ou processo seguro.'); } await admin.auth().setCustomUserClaims(user.uid,{role:'admin_valora',companyId:''}); await setDoc(db,'users',user.uid,{uid:user.uid,name:adminName,email:adminEmail,role:'admin_valora',companyId:'',status:'active',createdAt:now,updatedAt:now,migratedAt:now,source:SOURCE}); }
  const write = async (...x) => apply ? setDoc(db,...x) : console.log(`DRY create/merge ${x[0]}/${x[1]}`);
  for (const p of plans(now)) await write('plans',p.id,p); for (const m of modules(now)) await write('modules',m.id,m); for (const d of docs(now)) await write(...d); for (const a of kb(now)) await write('knowledgeBase',a.id,a); const s=support(now); for (const c of s.cats) await write('supportCategories',c.id,c); for (const p of s.slas) await write('supportSlaPolicies',p.id,p); if (seedDemoResponse) await write('responses','resp_bootstrap_demo',{id:'resp_bootstrap_demo',surveyId:SURVEY_ID,formId:FORM_ID,companyId:ORG_ID,isDemo:true,migratedFromBootstrap:true,createdAt:now,updatedAt:now,source:SOURCE}); console.log(`Link público gerado uma vez: /?survey=${SURVEY_ID}&token=${surveyToken}`); }
main().catch(err => { console.error(err); process.exit(1); });
